import React, { Suspense, lazy } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'sonner';
import { AuthProvider } from './contexts/AuthContext';
import { NotificationProvider } from './contexts/NotificationContext';
import { AppDataProvider } from './contexts/AppDataContext';
import { FormProvider } from './contexts/FormContext';
import ErrorBoundary from './components/layout/ErrorBoundary';
import LoadingSpinner from './components/ui/LoadingSpinner';
import ProtectedRoute from './components/layout/ProtectedRoute';
import PublicRoute from './components/layout/PublicRoute';
import { useAuth } from './contexts/AuthContext';

// Doctor feature components
import TodayAppointments from './features/doctor/TodayAppointments';
import ActivePatients from './features/doctor/ActivePatients';
import PendingReviews from './features/doctor/PendingReviews';

// Lazy load pages for better performance
const LandingPage = lazy(() => import('./pages/LandingPage'));
const Login = lazy(() => import('./pages/Login'));
const Register = lazy(() => import('./pages/Register'));
const PatientDashboard = lazy(() => import('./pages/PatientDashboard'));
const DoctorDashboard = lazy(() => import('./pages/DoctorDashboard'));
const AdminDashboard = lazy(() => import('./pages/AdminDashboard'));
const AppointmentScheduling = lazy(() => import('./pages/AppointmentScheduling'));
const ConsultationRecords = lazy(() => import('./pages/ConsultationRecords'));
const DoctorAvailability = lazy(() => import('./pages/DoctorAvailability'));
const NotificationsPage = lazy(() => import('./pages/NotificationsPage'));
const ProfileSettings = lazy(() => import('./pages/ProfileSettings'));
const Onboarding = lazy(() => import('./pages/Onboarding'));
const MainLayout = lazy(() => import('./components/layout/MainLayout'));

// Feature components
const AppointmentBooking = lazy(() => import('./features/appointments/AppointmentBooking'));
const ContactSupport = lazy(() => import('./features/contact/ContactSupport'));
const EmergencyContacts = lazy(() => import('./features/emergency/EmergencyContacts'));

// Fallback component for Suspense
const PageLoader = () => (
  <div className="min-h-screen flex items-center justify-center">
    <LoadingSpinner size="lg" />
  </div>
);

// Role-specific route components
const PatientRoutes = () => (
  <Routes>
    <Route path="dashboard" element={<PatientDashboard />} />
    <Route path="appointments" element={<AppointmentScheduling />} />
    <Route path="appointments/book" element={<AppointmentBooking />} />
    <Route path="consultations" element={<ConsultationRecords />} />
    <Route path="notifications" element={<NotificationsPage />} />
    <Route path="profile" element={<ProfileSettings />} />
    <Route path="*" element={<Navigate to="/app/patient/dashboard" replace />} />
  </Routes>
);

const DoctorRoutes = () => (
  <Routes>
    <Route path="dashboard" element={<DoctorDashboard />} />
    <Route path="today-appointments" element={<TodayAppointments />} />
    <Route path="active-patients" element={<ActivePatients />} />
    <Route path="pending-reviews" element={<PendingReviews />} />
    <Route path="appointments" element={<AppointmentScheduling />} />
    <Route path="availability" element={<DoctorAvailability />} />
    <Route path="consultations" element={<ConsultationRecords />} />
    <Route path="notifications" element={<NotificationsPage />} />
    <Route path="profile" element={<ProfileSettings />} />
    <Route path="*" element={<Navigate to="/app/doctor/dashboard" replace />} />
  </Routes>
);

const AdminRoutes = () => (
  <Routes>
    <Route path="dashboard" element={<AdminDashboard />} />
    <Route path="appointments" element={<AppointmentScheduling />} />
    <Route path="consultations" element={<ConsultationRecords />} />
    <Route path="notifications" element={<NotificationsPage />} />
    <Route path="profile" element={<ProfileSettings />} />
    <Route path="*" element={<Navigate to="/app/admin/dashboard" replace />} />
  </Routes>
);

// Role-based redirect component
const RoleBasedRedirect = () => {
  const { user } = useAuth();
  
  const dashboardRoutes = {
    patient: '/app/patient/dashboard',
    doctor: '/app/doctor/dashboard',
    admin: '/app/admin/dashboard'
  };
  
  const redirectPath = dashboardRoutes[user?.role] || '/app/patient/dashboard';
  
  return <Navigate to={redirectPath} replace />;
};

function App() {
  return (
    <ErrorBoundary>
      <AuthProvider>
        <AppDataProvider>
          <FormProvider>
            <Router>
              <NotificationProvider>
              <div className="App">
                <Suspense fallback={<PageLoader />}>
                  <Routes>
                    {/* Public Routes */}
                    <Route
                      path="/"
                      element={
                        <PublicRoute>
                          <LandingPage />
                        </PublicRoute>
                      }
                    />
                    <Route
                      path="/login"
                      element={
                        <PublicRoute>
                          <Login />
                        </PublicRoute>
                      }
                    />
                    <Route
                      path="/register"
                      element={
                        <PublicRoute>
                          <Register />
                        </PublicRoute>
                      }
                    />

                    {/* Protected Routes with Layout */}
                    <Route
                      path="/app"
                      element={
                        <ProtectedRoute>
                          <MainLayout />
                        </ProtectedRoute>
                      }
                    >
                      {/* Patient Routes */}
                      <Route path="patient/*" element={<ProtectedRoute allowedRoles={['patient']}><PatientRoutes /></ProtectedRoute>} />
                      
                      {/* Doctor Routes */}
                      <Route path="doctor/*" element={<ProtectedRoute allowedRoles={['doctor']}><DoctorRoutes /></ProtectedRoute>} />
                      
                      {/* Admin Routes */}
                      <Route path="admin/*" element={<ProtectedRoute allowedRoles={['admin']}><AdminRoutes /></ProtectedRoute>} />
                      
                      {/* Common routes accessible by all roles */}
                      <Route path="onboarding" element={<Onboarding />} />
                      <Route path="contact" element={<ContactSupport />} />
                      <Route path="emergency" element={<EmergencyContacts />} />
                    </Route>

                    {/* Redirect to appropriate dashboard based on user role */}
                    <Route
                      path="/dashboard"
                      element={<RoleBasedRedirect />}
                    />

                    {/* Fallback route */}
                    <Route path="*" element={<Navigate to="/" replace />} />
                  </Routes>
                </Suspense>

                {/* Global toast notifications */}
                <Toaster 
                  position="top-right"
                  expand={false}
                  richColors
                  closeButton
                />
              </div>
              </NotificationProvider>
            </Router>
          </FormProvider>
        </AppDataProvider>
      </AuthProvider>
    </ErrorBoundary>
  );
}

export default App;
