// Simulate API delay
const simulateDelay = (ms = 500) => new Promise(resolve => setTimeout(resolve, ms));

// Helper functions to reduce code duplication
const filterByDoctorId = (items, doctorId) => items.filter(item => item.doctorId === doctorId);
const filterByDateAndDoctor = (items, doctorId, date) => items.filter(item => item.doctorId === doctorId && item.date === date);
const getUniquePatientIds = (appointments) => [...new Set(appointments.map(apt => apt.patientId))];

// Mock API functions
export const searchDoctors = async (query) => {
  await simulateDelay();
  
  if (!query || query.length < 2) {
    return mockDoctors;
  }
  
  const lowercaseQuery = query.toLowerCase();
  return mockDoctors.filter(doctor => 
    doctor.name.toLowerCase().includes(lowercaseQuery) ||
    doctor.specialization.toLowerCase().includes(lowercaseQuery) ||
    doctor.degrees.some(degree => degree.toLowerCase().includes(lowercaseQuery))
  );
};

export const getDoctorById = async (id) => {
  await simulateDelay();
  return mockDoctors.find(doctor => doctor.id === id);
};

export const getAvailableSlots = async (doctorId, date) => {
  await simulateDelay();
  
  const doctor = mockDoctors.find(d => d.id === doctorId);
  if (!doctor) return [];
  
  // Filter out already booked slots (simulate existing bookings)
  const bookedSlots = mockAppointments
    .filter(apt => apt.doctorId === doctorId && apt.date === date)
    .map(apt => apt.time);
  
  return doctor.availableSlots.filter(slot => !bookedSlots.includes(slot));
};

export const bookAppointment = async (appointmentData) => {
  await simulateDelay();
  
  // Simulate booking logic
  const newAppointment = {
    id: `apt-${Date.now()}`,
    ...appointmentData,
    status: 'pending',
    createdAt: new Date().toISOString()
  };
  
  // In real app, this would make an API call
  mockAppointments.push(newAppointment);
  
  return { success: true, appointment: newAppointment };
};

