// Doctor Dashboard API Functions
export const getTodayAppointments = async (doctorId) => {
  await simulateDelay();
  const demoToday = '2025-01-13';
  return filterByDateAndDoctor(mockAppointments, doctorId, demoToday);
};

export const getActivePatients = async (doctorId) => {
  await simulateDelay();
  
  const doctorAppointments = filterByDoctorId(mockAppointments, doctorId);
  const patientIds = getUniquePatientIds(doctorAppointments);
  
  return mockPatients.filter(patient => 
    patientIds.includes(patient.id) && patient.status === 'active'
  );
};

export const getPendingReviews = async (doctorId) => {
  await simulateDelay();
  
  return mockMedicalReviews.filter(review => 
    review.doctorId === doctorId && review.status === 'pending'
  );
};

export const getDoctorAvailability = async (doctorId) => {
  await simulateDelay();
  return mockDoctorAvailability;
};

export const updateReviewStatus = async (reviewId, status, doctorNotes = '') => {
  await simulateDelay();
  
  const review = mockMedicalReviews.find(r => r.id === reviewId);
  if (review) {
    review.status = status;
    review.doctorNotes = doctorNotes;
    review.reviewedAt = new Date().toISOString();
  }
  
  return { success: true, review };
};

export const getDashboardStats = async (doctorId) => {
  await simulateDelay();
  
  const demoToday = '2025-01-13';
  const doctorAppointments = filterByDoctorId(mockAppointments, doctorId);
  const todayAppointments = filterByDateAndDoctor(mockAppointments, doctorId, demoToday);
  const patientIds = getUniquePatientIds(doctorAppointments);
  const activePatients = mockPatients.filter(patient => 
    patientIds.includes(patient.id) && patient.status === 'active'
  );
  const pendingReviews = filterByDoctorId(mockMedicalReviews, doctorId)
    .filter(review => review.status === 'pending');
  
  return {
    todayAppointmentsCount: todayAppointments.length,
    activePatientsCount: activePatients.length,
    pendingReviewsCount: pendingReviews.length,
    availableHoursToday: mockDoctorAvailability.availableHoursToday
  };
};

