// Generate patient-specific consultation records
export const generatePatientRecords = (patientId) => {
  // Filter all doctor consultation records for this specific patient
  const patientConsultations = doctorConsultationRecords.filter(record => record.patientId === patientId);
  
  // Map to patient view format
  return patientConsultations.map(record => ({
    id: record.id,
    date: record.date,
    time: record.time,
    doctor: record.doctorName,
    type: record.type,
    diagnosis: record.diagnosis,
    prescription: Array.isArray(record.prescription) 
      ? record.prescription.map(med => `${med.medication} ${med.dosage} - ${med.frequency}`).join('; ') 
      : record.prescription,
    status: record.status,
    notes: record.notes,
    chiefComplaint: record.chiefComplaint,
    followUp: record.followUp,
    labResults: record.labResults
  }));
};

