// Real User Service wired to backend via API Gateway
import api from './api';

const TOKEN_KEY = 'healthcare_token';
const USER_KEY = 'healthcare_user';

const saveSession = (token, user) => {
  if (token) localStorage.setItem(TOKEN_KEY, token);
  if (user) localStorage.setItem(USER_KEY, JSON.stringify(user));
};

const clearSession = () => {
  localStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(USER_KEY);
};

class UserService {
  // Authentication
  async login(email, password) {
    // 1) Login -> get JWT
    const loginRes = await api.post('/app1/api/v1/user/login', {
      emailId: email,
      password,
    });
    const token = loginRes.data?.token;
    if (!token) throw new Error('No token returned');

    // 2) Validate token -> get email and role
    const validateRes = await api.get('/app1/api/v1/user/validate-token', {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!validateRes.data?.valid) throw new Error('Invalid token');

    const emailId = validateRes.data.emailId || email;
    const role = (validateRes.data.userRole || '').toString().toLowerCase();

    // 3) Fetch full user profile
    const userRes = await api.get(`/app1/api/v1/user/${encodeURIComponent(emailId)}`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    const userDto = userRes.data || {};

    const user = {
      id: emailId,
      user_id: emailId,
      email: emailId,
      role,
      name: userDto.name || emailId,
    };

    saveSession(token, user);

    return { data: { ...user, token } };
  }

  async register(userData) {
    const payload = {
      emailId: userData.email,
      password: userData.password,
      userRole: (userData.role || 'patient').toUpperCase(),
      name: userData.name,
      dateOfBirth: userData.dateOfBirth,
      gender: userData.gender,
      phoneNumber: userData.phoneNumber,
      address: userData.address,
      avatar: userData.avatar,
    };

    const res = await api.post('/app1/api/v1/user/register', payload);
    return { data: res.data };
  }

  // Backward-compatible method used by Register.js
  async addUsers(formData) {
    return this.register(formData);
  }

  async logout() {
    clearSession();
    return { success: true };
  }

  async getCurrentUser() {
    const token = localStorage.getItem(TOKEN_KEY);
    if (!token) throw new Error('No authenticated user');

    const validateRes = await api.get('/app1/api/v1/user/validate-token', {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!validateRes.data?.valid) throw new Error('Invalid session');

    const emailId = validateRes.data.emailId;
    const role = (validateRes.data.userRole || '').toString().toLowerCase();

    const userRes = await api.get(`/app1/api/v1/user/${encodeURIComponent(emailId)}`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    const dto = userRes.data || {};

    const user = {
      id: emailId,
      user_id: emailId,
      email: emailId,
      role,
      name: dto.name || emailId,
    };

    saveSession(token, user);
    return { data: user };
  }

  isAuthenticated() {
    return !!localStorage.getItem(TOKEN_KEY);
  }

  getToken() {
    return localStorage.getItem(TOKEN_KEY);
  }

  getUserRole() {
    const user = localStorage.getItem(USER_KEY);
    return user ? JSON.parse(user).role : null;
  }
}

export default new UserService();
