import React, { createContext, useContext, useState } from 'react';
import UserService from '../services/UserService';
 
const AuthContext = createContext(undefined);
 
export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [showOnboarding, setShowOnboarding] = useState(false);
 
  const login = async (email, password) => {
    try {
      const res = await UserService.login(email, password);
      // The backend returns user data; set it in context
      setUser({
        id: res.data.user_id || res.data.id,
        name: res.data.name || res.data.email,
        email: res.data.email,
        role: res.data.role,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${res.data.email}`,
      });
    } catch (err) {
      throw err; // Let the UI handle error display
    }
  };
 
  const register = async (userData) => {
    await UserService.register(userData);
    setShowOnboarding(true);
  };
 
  const logout = () => {
    setUser(null);
    setShowOnboarding(false);
  };
 
  const completeOnboarding = () => {
    setShowOnboarding(false);
    if (user) {
      setUser({ ...user, isNewUser: false });
    }
  };
 
  const updateUser = (userData) => {
    if (user) {
      setUser({ ...user, ...userData });
    }
  };
 
  return (
    <AuthContext.Provider value={{
      user,
      isAuthenticated: !!user,
      showOnboarding,
      login,
      register,
      logout,
      completeOnboarding,
      updateUser,
    }}>
      {children}
    </AuthContext.Provider>
  );
}
 
export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}
 